VALUES
  ('aboriginal-5ff21eeb-moex-00222', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-110-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '下列關於區分地上權排他效力之敘述，何者正確？', '["土地所有人於同一土地設定區分地上權後，應得該區分地上權人同意，始得再設定用益物權或 另一區分地上權", "土地所有人於同一土地設定區分地上權後，即不許其再設定用益物權或另一區分地上權", "土地所有人於同一土地設定區分地上權後，毋庸該區分地上權人同意，亦得再設定用益物權或 另一區分地上權", "土地所有人於同一土地設定區分地上權後，即不許其再設定用益物權，僅得於未重疊之空間範 圍設定另一區分地上權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:13+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00223', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-110-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '關於婚姻之要件及其效力，下列敘述，何者正確？', '["結婚應以書面為之，並有2人以上證人之簽名與公開之儀式後，攜公開儀式之影音照片，至法 院公證處為登記，該婚姻始生效力", "有配偶者重婚時，前婚姻應經後婚之當事人請求法院裁定為無效", "未成年人結婚，未得法定代理人同意時，其法定代理人應於知悉後2年內，向法院請求撤銷之。 但未成年人已分居者，不在此限", "結婚撤銷之效力，不溯及既往"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:13+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00224', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-110-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲被乙男收養為養子後，丙男又收養甲為養子，請問其收養的效力為何？', '["無效", "有效", "效力未定", "得撤銷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:13+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00225', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-110-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '下列關於遺囑之敘述，何者屬於遺囑全部或一部失效，而非無效之情形？', '["在自書遺囑中，遺囑人以蓋章代替簽名", "立密封遺囑時，兩位見證人中之一人，為受輔助宣告人", "15歲之遺囑人，得其法定代理人之同意，作成自書遺囑", "遺囑人遺贈財產於第三人，但第三人先於遺囑人死亡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:13+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00226', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-110-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '下列關於遺產效力之敘述，何者錯誤？', '["民法第1150條所稱遺產管理之費用，具有共益之性質", "民法第1150條所稱遺產管理之費用，具有個別利益之性質", "遺產未分割前，得由繼承人互推一人管理之", "繼承人有數人時，在分割遺產前，各繼承人對於遺產全部為公同共有"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:13+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00227', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-110-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '甲有子女乙丙丁戊四人。丙有子女丙1丙2二人。戊有子女戊1戊2戊3三人。乙丙一同出遊遇 難，甲聽聞噩耗悲痛猝逝，甲有遺產新臺幣（下同）3600萬元。戊發現甲所留下遺囑中指定乙繼 承其中半數，戊動手塗改，隨即被丁發現。下列敘述，何者正確？', '["丁得繼承900萬元", "戊得繼承1800萬元", "戊2得繼承600萬元", "丙2得繼承600萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:13+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00228', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-110-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '下列何種法人之機關，僅存在於社團？', '["董事", "監察人", "清算人", "社員總會"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:13+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('aboriginal-5ff21eeb-moex-00229', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-110-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', 'A地上有4棵果樹，其中3棵被砍斷後，於此情形，有幾個獨立物？', '["1個", "2個", "3個", "4個"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:13+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL),
