  ('aboriginal-5ff21eeb-moex-00231', 'aboriginal-5ff21eeb', 'aboriginal-5ff21eeb-moex-110-9b7ab1bb', 'sub-aboriginal-5ff21eeb-01', NULL, 'single_choice', '使用借貸契約中，借用人保管借用物，應負何種責任？', '["故意責任", "故意或重大過失責任", "具體輕過失責任", "抽象輕過失責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:13+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅法務"}'::jsonb, NULL)
